import './App.css';
import { useState } from 'react';

import SchedulerForm from './components/SchedulerForm';
import SimulationBoard from './components/SimulationBoard';
import ResultsDisplay from './components/ResultsDisplay';

import { fcfs } from './algorithms/fcfs';
import FCFSChart from './components/FCFSChart';

function App() {
  const [result, setResult] = useState(null);

  const handleFCFS = (requests, head) => {
    const output = fcfs(requests, head);
    setResult(output);
  };

  return (
    <div className="App" style={{ padding: '2rem' }}>
      <h1>Job Scheduling Simulator</h1>

      {/* Form to take input */}
      <SchedulerForm onCalculate={handleFCFS} />

      {/* Static simulation board (optional UI section) */}
      <SimulationBoard />

      {/* Display results once available */}
      {result && (
        <>
          <ResultsDisplay result={result} />
          <FCFSChart sequence={result.sequence} />
        </>
      )}
    </div>
  );
}

export default App;
